# PROTOTYPE - priority queue behaviour explorer
import heapq

class NotificationQueue:
    def __init__(self):
        self._queue = []

    def add(self, msg, priority=0):
        heapq.heappush(self._queue, (-priority, msg))

    def process_next(self):
        if not self._queue:
            return None
        return heapq.heappop(self._queue)[1]

    def __len__(self):
        return len(self._queue)

def main():
    q = NotificationQueue()
    q.add('Server update available', priority=1)
    q.add('New comment on your post', priority=0)
    q.add('URGENT: Payment failed', priority=5)
    q.add('Weekly digest ready', priority=-1)

    print('Queue state (processing order):')
    while len(q) > 0:
        notification = q.process_next()
        print(f'  -> {notification}')

if __name__ == '__main__':
    main()
```

State is printed after every dequeue. Conclusion: priority queue works, urgent notifications naturally skip ahead.
